mapper.update:
UPDATE `comment`
SET content = #{content}, modified_date = NOW()
WHERE id = #{commentId}
  AND user_id = #{userId}
  AND is_deleted = 0

mapper.delete:
UPDATE `comment`
SET is_deleted = 1, modified_date = NOW()
WHERE post_id = #{postId}
  AND user_id = #{userId}
  AND id = #{commentId}
  AND is_deleted = 0
